INSERT INTO questions (question_text, choices, correct_answer, explanation, subject, topic, difficulty, exam_type) VALUES
('What does the word "benevolent" mean?', '["Kind and generous", "Hostile and aggressive", "Clever and cunning", "Lazy and indifferent"]', 'A', 'Benevolent means well-meaning and kindly; generous in giving to others. From Latin: bene (well) + volent (wishing).', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which sentence uses correct subject-verb agreement?', '["The team is playing well.", "The team are playing well.", "The teams is playing well.", "The team have playing well."]', 'A', '"The team" is a collective noun treated as singular in American English. The correct verb is "is."', 'English', 'Writing', 'medium', 'secondary'),
('What does the prefix "mis-" mean in the word "misunderstand"?', '["Wrongly", "Again", "Before", "Not"]', 'A', 'The prefix "mis-" means wrongly or badly, as in misunderstand (to understand wrongly), mistake, or misuse.', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is the correct punctuation for this sentence: "I need to buy eggs milk and bread."', '["I need to buy eggs, milk, and bread.", "I need to buy eggs milk, and bread.", "I need to buy eggs: milk and bread.", "I need to buy eggs milk, and bread,"]', 'A', 'Items in a series should be separated by commas. The Oxford comma (before "and") is used: eggs, milk, and bread.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "ambiguous" mean?', '["Having more than one possible interpretation", "Clear and straightforward", "Factually incorrect", "Highly emotional"]', 'A', 'Ambiguous means open to more than one interpretation; having a double meaning or being unclear.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the purpose of a thesis statement in an essay?', '["To present the main argument of the essay", "To provide background information", "To summarize each body paragraph", "To conclude the essay"]', 'A', 'A thesis statement presents the main argument or central claim of the essay, typically at the end of the introduction paragraph.', 'English', 'Writing', 'easy', 'secondary'),
('Which of the following is a synonym for "eloquent"?', '["Articulate", "Verbose", "Quiet", "Hesitant"]', 'A', 'Eloquent means fluent or persuasive in speaking or writing. A synonym is "articulate" — able to express clearly.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the correct way to write a possessive form for a singular noun ending in "s" (like "James")?', '["James''s or James''", "Jamess", "James", "Jamess''"]', 'A', 'For singular nouns ending in "s," both James''s and James'' are acceptable. Most style guides prefer James''s.', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "tenacious" mean?', '["Holding firmly to something; persistent", "Easily giving up", "Very intelligent", "Quiet and shy"]', 'A', 'Tenacious means holding firmly to a course of action or belief; persistent and determined. From Latin: tenax (holding fast).', 'English', 'Vocabulary', 'medium', 'secondary'),
('What type of writing aims to convince the reader to accept a particular viewpoint?', '["Persuasive writing", "Descriptive writing", "Narrative writing", "Expository writing"]', 'A', 'Persuasive writing is designed to convince the reader to adopt a specific point of view or take a specific action, using arguments and evidence.', 'English', 'Writing', 'easy', 'secondary'),
('What does the suffix "-ology" mean?', '["Study of", "Without", "Full of", "Related to"]', 'A', 'The suffix "-ology" means the study of something (e.g., biology = study of life, psychology = study of mind).', 'English', 'Vocabulary', 'easy', 'secondary'),
('Which sentence contains a dangling modifier?', '["Running late, he missed the bus.", "Running late, the bus was missed.", "He ran late and missed the bus.", "Because he ran late, he missed the bus."]', 'A', 'A dangling modifier has no clear subject to modify. "Running late, the bus was missed" — the bus cannot run late, so "running late" dangles.', 'English', 'Writing', 'hard', 'secondary'),
('What does the word "euphemism" mean?', '["A mild expression substituted for a harsh one", "An extremely offensive term", "A foreign borrowed word", "A word with the same meaning as another"]', 'A', 'A euphemism is a mild or indirect expression used in place of one that might be considered harsh or blunt (e.g., "passed away" for "died").', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the function of a "topic sentence" in a paragraph?', '["To state the main idea of the paragraph", "To provide the conclusion", "To give an example", "To introduce the essay"]', 'A', 'A topic sentence states the controlling idea of a paragraph. It is usually the first sentence and tells the reader what the paragraph is about.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "verbose" mean?', '["Using more words than necessary", "Speaking clearly and concisely", "Keeping quiet", "Writing with vivid imagery"]', 'A', 'Verbose means using or expressed in more words than are needed; wordy. Antonym: concise.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the correct form of the verb in: "Either the students or the teacher __ responsible."', '["is", "are", "were", "have been"]', 'A', 'When subjects are joined by "either...or," the verb agrees with the subject closest to it. "Teacher" is singular, so the verb is "is."', 'English', 'Writing', 'hard', 'secondary'),
('What does the word "ambivalent" mean?', '["Having mixed feelings about something", "Strongly in favor of something", "Strongly against something", "Completely neutral and uninvolved"]', 'A', 'Ambivalent means having mixed or contradictory feelings about something. From Latin: ambi (both) + valent (strength).', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which type of essay presents both sides of an issue objectively?', '["Expository essay", "Narrative essay", "Descriptive essay", "Persuasive essay"]', 'A', 'An expository essay explains or informs objectively, presenting facts and multiple perspectives without personal opinion.', 'English', 'Writing', 'medium', 'secondary'),
('What does the prefix "anti-" mean?', '["Against", "Before", "Under", "Over"]', 'A', 'The prefix "anti-" means against or opposed to (e.g., antibiotics = against bacteria, antisocial = against social norms).', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is "parallel structure" in writing?', '["Using the same grammatical form for items in a list or series", "Repeating the same word multiple times", "Using synonyms throughout a paragraph", "Writing sentences of equal length"]', 'A', 'Parallel structure (parallelism) requires using the same grammatical form for words, phrases, or clauses in a series (e.g., "I like swimming, running, and hiking" — all gerunds).', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "pragmatic" mean?', '["Dealing with things sensibly and practically", "Idealistic and unrealistic", "Emotional and dramatic", "Theoretical and abstract"]', 'A', 'Pragmatic means dealing with things practically based on what works rather than following theories or ideals.', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which sentence has correct comma usage with an introductory clause?', '["After the storm, the streets were flooded.", "After the storm the streets were flooded.", "After the storm; the streets were flooded.", "After the storm: the streets were flooded."]', 'A', 'An introductory adverbial clause should be followed by a comma. "After the storm," is an introductory clause.', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "lucid" mean?', '["Clear and easy to understand", "Dark and mysterious", "Complex and confusing", "Slow and hesitant"]', 'A', 'Lucid means expressed clearly; easy to understand. Can also mean mentally clear and coherent.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the purpose of a "hook" in an essay introduction?', '["To capture the reader''s attention", "To present the thesis", "To list all supporting points", "To conclude the introduction"]', 'A', 'A hook is an opening sentence or passage designed to grab the reader''s interest. It can be a question, quote, anecdote, or surprising fact.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "coerce" mean?', '["To force someone to do something", "To convince someone politely", "To help someone voluntarily", "To prevent someone from acting"]', 'A', 'Coerce means to compel someone to do something by using force, threats, or pressure; to use coercion.', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which of these is an example of a run-on sentence?', '["I went to school, but I forgot my homework.", "I went to school I forgot my homework.", "Although I forgot my homework, I still went to school.", "I forgot my homework, so I stayed home."]', 'A', 'A run-on sentence occurs when two independent clauses are joined without proper punctuation or a conjunction. "I went to school I forgot my homework" is a run-on (fused sentence).', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "meticulous" mean?', '["Very careful and precise", "Careless and sloppy", "Extremely fast", "Somewhat curious"]', 'A', 'Meticulous means showing great attention to detail or being very careful and precise about minor details.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the term for writing that tells a personal story or experience?', '["Narrative writing", "Expository writing", "Persuasive writing", "Technical writing"]', 'A', 'Narrative writing tells a story (real or fictional) with characters, plot, setting, and conflict. Personal narratives recount the writer''s own experiences.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "altruistic" mean?', '["Showing concern for others'' wellbeing without personal gain", "Acting purely for personal benefit", "Feeling intense jealousy", "Being cautious and careful"]', 'A', 'Altruistic means showing selfless concern for the wellbeing of others. It is the opposite of selfish or egotistical.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is the correct sentence?', '["She doesn''t know where he is.", "She don''t know where he is.", "She not knowing where he is.", "She didn''t knew where he is."]', 'A', '"She doesn''t know where he is" is correct. "Doesn''t" (does not) is the correct third-person singular present negative form.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "vindictive" mean?', '["Having a strong desire for revenge", "Extremely forgiving", "Very cautious", "Exceedingly generous"]', 'A', 'Vindictive means having or showing a strong or unreasonable desire for revenge; spiteful.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is "descriptive writing"?', '["Writing that uses sensory details to create a vivid picture", "Writing that argues a point of view", "Writing that tells a chronological story", "Writing that explains a process"]', 'A', 'Descriptive writing uses sensory details (sight, sound, smell, taste, touch) and vivid language to create a clear picture of a person, place, object, or event.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "apprehensive" mean?', '["Worried or uneasy about something that might happen", "Confident and relaxed", "Extremely happy", "Confused and disoriented"]', 'A', 'Apprehensive means anxious or fearful about a future event; worried about possible consequences.', 'English', 'Vocabulary', 'easy', 'secondary'),
('Which of the following is an example of a compound sentence?', '["She studied hard, so she passed the exam.", "She studied hard to pass the exam.", "Studying hard, she passed the exam.", "Because she studied hard, she passed."]', 'A', 'A compound sentence joins two independent clauses with a coordinating conjunction (FANBOYS). "She studied hard, so she passed" has two independent clauses joined by "so."', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "diligent" mean?', '["Hardworking and careful", "Lazy and careless", "Quick and impulsive", "Quiet and reserved"]', 'A', 'Diligent means having or showing care and conscientiousness in one''s work or duties; hardworking.', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is the difference between "affect" and "effect"?', '["''Affect'' is usually a verb; ''effect'' is usually a noun", "They mean the same thing", "''Effect'' is the verb; ''affect'' is the noun", "''Affect'' is only used in science"]', 'A', 'Affect is usually a verb meaning to influence or impact. Effect is usually a noun meaning a result or outcome. (Exception: "to effect change" uses effect as a verb meaning to bring about.)', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "skeptical" mean?', '["Not easily convinced; doubtful", "Easily convinced and trusting", "Very enthusiastic", "Completely neutral"]', 'A', 'Skeptical means having doubts or reservations; not easily convinced; questioning the truth of something.', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is the correct use of a semicolon?', '["To join two closely related independent clauses", "To introduce a list after a complete sentence", "To separate items in a simple list", "To indicate a pause shorter than a comma"]', 'A', 'A semicolon (;) joins two closely related independent clauses: "She loves reading; her brother prefers sports."', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "phenomenon" (plural: phenomena) mean?', '["A remarkable or observable fact or occurrence", "An imaginary event", "A scientific theory", "A historical document"]', 'A', 'A phenomenon is a fact or situation observed to exist or happen, especially one whose cause is unexplained or extraordinary.', 'English', 'Vocabulary', 'medium', 'secondary'),
('What is "expository writing" primarily designed to do?', '["Inform and explain a topic clearly", "Tell a creative story", "Argue for a position", "Describe a scene vividly"]', 'A', 'Expository writing aims to explain, describe, give information, or inform the reader about a topic in a clear and logical manner.', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "condescending" mean?', '["Acting superior or patronizing toward others", "Treating others as equals", "Being extremely humble", "Being overly friendly"]', 'A', 'Condescending means behaving as if one is superior or looking down on others; patronizing.', 'English', 'Vocabulary', 'medium', 'secondary'),
('Which of the following correctly uses a colon?', '["She brought three things: her book, pencil, and eraser.", "She brought: three things.", "She brought: her book, pencil, and eraser.", "She: brought three things."]', 'A', 'A colon is used after a complete sentence to introduce a list or explanation. "She brought three things:" is a complete clause, so the colon use is correct.', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "infer" mean?', '["To draw a conclusion from evidence", "To state directly", "To quote from a source", "To summarize a text"]', 'A', 'To infer means to derive a conclusion from evidence and reasoning rather than from explicit statements.', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is the term for the emotional appeal used in persuasive writing?', '["Pathos", "Logos", "Ethos", "Kairos"]', 'A', 'Pathos is an appeal to the audience''s emotions. Logos appeals to logic, ethos appeals to credibility, and kairos appeals to timing.', 'English', 'Writing', 'hard', 'secondary'),
('What does the word "resilient" mean?', '["Able to recover quickly from difficulties", "Easily broken or damaged", "Slow to respond to change", "Extremely fragile"]', 'A', 'Resilient means able to recover quickly from difficulties; tough and adaptable.', 'English', 'Vocabulary', 'easy', 'secondary'),
('What is a "transition" in writing?', '["A word or phrase connecting ideas between sentences or paragraphs", "The opening sentence of a paragraph", "A synonym used to avoid repetition", "The closing statement of an essay"]', 'A', 'Transitions are words, phrases, or sentences that connect ideas and guide the reader from one point to the next (e.g., "however," "in addition," "therefore").', 'English', 'Writing', 'easy', 'secondary'),
('What does the word "concise" mean?', '["Brief and clear, using few words", "Long and detailed", "Vague and unclear", "Repetitive and wordy"]', 'A', 'Concise means expressing a lot in few words; brief and clear. The opposite is verbose or wordy.', 'English', 'Vocabulary', 'easy', 'secondary'),
('Which of the following is a complex sentence?', '["Although it rained, we enjoyed the picnic.", "It rained and we stayed inside.", "It rained. We stayed inside.", "We stayed inside, for it rained."]', 'A', 'A complex sentence has one independent clause and at least one dependent (subordinate) clause. "Although it rained" is a dependent clause.', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "nuance" mean?', '["A subtle difference or distinction", "A major obvious difference", "A bold exaggeration", "A complete absence of meaning"]', 'A', 'Nuance refers to a subtle difference or shade of meaning, expression, or sound — a fine distinction.', 'English', 'Vocabulary', 'hard', 'secondary'),
('What does "active voice" mean in writing?', '["The subject performs the action of the verb", "The subject receives the action", "The verb tense is present", "Emotions are expressed directly"]', 'A', 'In active voice, the subject does the action: "Maria wrote the report." In passive voice, the subject receives the action: "The report was written by Maria."', 'English', 'Writing', 'medium', 'secondary'),
('What does the word "empathy" mean?', '["The ability to understand and share another person''s feelings", "Feeling sorry for someone from a distance", "Strong personal self-awareness", "Complete indifference to others"]', 'A', 'Empathy is the capacity to understand and share the feelings of another person, as if experiencing their emotions firsthand.', 'English', 'Vocabulary', 'easy', 'secondary');
